mapper.select:
SELECT employee_id, username, password, boss_role 
FROM employee 
WHERE username = #{username}

mapper.insert:
INSERT INTO boss_subordinates (boss_id, subordinate_id)
SELECT boss_id, #{subordinateId}
FROM boss
WHERE employee_id = #{bossId}

mapper.update:
UPDATE employee 
SET boss_id = 1 
WHERE boss_id = #{id}
